class Answer:
    text: str
    provenance: list[Provenance]
    constraints: list[str] | None = None
    token_usage: dict[str, int] | None = None

    def __post_init__(self):
        if self.constraints is None:
            self.constraints = []
        if self.token_usage is None:
            self.token_usage = {}

